from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple
from datetime import datetime
from collections import defaultdict

@dataclass
class Order:
    order_id: str
    side: str
    price: float
    quantity: float
    timestamp: datetime = field(default_factory=datetime.now)

class OrderBook:
    def __init__(self, symbol: str):
        self.symbol = symbol
        self.bids: Dict[float, List[Order]] = defaultdict(list)
        self.asks: Dict[float, List[Order]] = defaultdict(list)
        self.orders: Dict[str, Order] = {}

    def add_order(self, order: Order) -> List[Tuple[str, str, float, float]]:
        trades = []

        if order.side == "bid":
            # Match against asks
            ask_prices = sorted(self.asks.keys())
            for ask_price in ask_prices:
                if order.quantity <= 0 or ask_price > order.price:
                    break

                remaining = []
                for ask_order in self.asks[ask_price]:
                    if order.quantity <= 0:
                        remaining.append(ask_order)
                        continue

                    trade_qty = min(order.quantity, ask_order.quantity)
                    trades.append((order.order_id, ask_order.order_id, ask_price, trade_qty))

                    order.quantity -= trade_qty
                    ask_order.quantity -= trade_qty

                    if ask_order.quantity > 0:
                        remaining.append(ask_order)
                    else:
                        del self.orders[ask_order.order_id]

                if remaining:
                    self.asks[ask_price] = remaining
                else:
                    del self.asks[ask_price]
        else:
            # Match against bids
            bid_prices = sorted(self.bids.keys(), reverse=True)
            for bid_price in bid_prices:
                if order.quantity <= 0 or bid_price < order.price:
                    break

                remaining = []
                for bid_order in self.bids[bid_price]:
                    if order.quantity <= 0:
                        remaining.append(bid_order)
                        continue

                    trade_qty = min(order.quantity, bid_order.quantity)
                    trades.append((bid_order.order_id, order.order_id, bid_price, trade_qty))

                    order.quantity -= trade_qty
                    bid_order.quantity -= trade_qty

                    if bid_order.quantity > 0:
                        remaining.append(bid_order)
                    else:
                        del self.orders[bid_order.order_id]

                if remaining:
                    self.bids[bid_price] = remaining
                else:
                    del self.bids[bid_price]

        # Add remaining to book
        if order.quantity > 0:
            self.orders[order.order_id] = order
            if order.side == "bid":
                self.bids[order.price].append(order)
            else:
                self.asks[order.price].append(order)

        return trades

    def cancel_order(self, order_id: str) -> bool:
        if order_id not in self.orders:
            return False

        order = self.orders[order_id]
        del self.orders[order_id]

        if order.side == "bid":
            self.bids[order.price] = [o for o in self.bids[order.price] if o.order_id != order_id]
            if not self.bids[order.price]:
                del self.bids[order.price]
        else:
            self.asks[order.price] = [o for o in self.asks[order.price] if o.order_id != order_id]
            if not self.asks[order.price]:
                del self.asks[order.price]

        return True

    def get_best_bid(self) -> Optional[Tuple[float, float]]:
        if not self.bids:
            return None
        best_price = max(self.bids.keys())
        total_qty = sum(o.quantity for o in self.bids[best_price])
        return (best_price, total_qty)

    def get_best_ask(self) -> Optional[Tuple[float, float]]:
        if not self.asks:
            return None
        best_price = min(self.asks.keys())
        total_qty = sum(o.quantity for o in self.asks[best_price])
        return (best_price, total_qty)

    def get_spread(self) -> Optional[float]:
        best_bid = self.get_best_bid()
        best_ask = self.get_best_ask()
        if best_bid and best_ask:
            return best_ask[0] - best_bid[0]
        return None

# Test
book = OrderBook("AAPL")
book.add_order(Order("b1", "bid", 149.90, 100))
book.add_order(Order("b2", "bid", 149.85, 200))
book.add_order(Order("a1", "ask", 150.10, 100))
book.add_order(Order("a2", "ask", 150.05, 150))

print(f"Best Bid: {book.get_best_bid()}")
print(f"Best Ask: {book.get_best_ask()}")
print(f"Spread: {book.get_spread()}")

trades = book.add_order(Order("b3", "bid", 150.10, 200))
print(f"Trades: {trades}")
